command.text:
&Set;
if not exists (select 1 from v20dmmaubc where ma_maubc = '&defaultForm;' and form = @c) begin declare @$recordHasBeenChanged nvarchar(512) select @$recordHasBeenChanged = case when @@language = 'v' then N'Mẫu báo cáo đã được xóa.' else N'Report form has been deleted.' end select 'ma_so' as field, @$recordHasBeenChanged as message return end if exists(select * from @@table where ma_so = @ma_so and form = @form) begin select 'ma_so' as field, replace(@$exists, '%s', rtrim(@ma_so)) as message return end
&Check;


objectBehavior$Dir$Irregular.checkCode(this, 'ma_so');
if (this._checked) {
  var v = (this._language == 'v'), k = this.getItem('kind').value, s = this.getItem('nguon').value, t = this.getItem('type').value;
  if (k == 1 && ((s == 1) || (s == 3)) && t != 1) {
    this._errorObject = this.getItem('type');
    e = (v ? 'Trường <span class="Highlight">' + this.getItem('type').field.HeaderText + '</span> không đúng.' : '<span class="Highlight">' + this.getItem('type').field.HeaderText + '</span> is invalid.');
    this._checked = false;
    $message.show(e, String.format('$find(\'{0}\')._errorObject.focus()', this.get_id()));
  }
}

script.text:

function loadFormDir(f) {
  changeLookupReadonly(f, 'ds_bp', true);
  changeLookupReadonly(f, 'ds_loai_lg', true);
  changeLookupReadonly(f, 'ds_sp', true);
  changeLookupReadonly(f, 'ds_pc', true);
  changeLookupReadonly(f, 'ds_cong', true);
  changeLookupReadonly(f, 'ds_tp', true);
  changeLookupReadonly(f, 'ds_tn_gt', true);

  if (f._action == 'Edit') setItemDisable(f, 'ma_so', true);
    else if (f._action == 'New') setItemDisable(f, 'ma_so', false);
  if (f._action != 'View') onChange$CalculateType(f);

  f._tabContainer.add_activeTabChanged(onChange$Tab);
  f._tabContainer._loaded = true;
}
function close$FormDir(f) {if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onChange$Tab);} catch (ex) {}}

function onChange$Tab(sender, e) {sender.parentForm.focusWhenTabChanged(['kind', 'chi_tieu2']);}
function onChange$Item(o) {
  var f = o.parentForm, name = o.field.Name;
  switch (name) {
    case 'nguon':
      onChange$Source(f, true);
      if (f.getItem('nguon').value != 2) f.setItemValue('type', 1);
      break;
    case 'kind':
      onChange$CalculateType(f, true);
      break; 
    default:
      break;
  }
}
function onChange$Source(f, force) {window.setTimeout(String.format('onFocus$Source(\'{0}\', {1});', f._id, force ? 1 : 0), 2);}
function onFocus$Source(id, force) {
  var f = $find(id), v = true, s = f.getItem('nguon').value, t;
  switch (s) {
    case '1':
      setItemDisable(f, 'ds_bp, ds_loai_lg', !v);
      setItemDisable(f, 'ds_sp, ds_pc, ds_cong, ds_tp, ds_tn_gt', v);
      setFieldsEmpty(f, 'ds_sp, ds_pc, ds_cong, ds_tp, ds_tn_gt', !v);
      break;
    case '2':
      setItemDisable(f, 'ds_bp, ds_loai_lg, ds_sp', !v);
      setItemDisable(f, 'ds_pc, ds_cong, ds_tp, ds_tn_gt', v);
      setFieldsEmpty(f, 'ds_pc, ds_cong, ds_tp, ds_tn_gt', !v);
      break;
    case '3':
      setItemDisable(f, 'ds_bp, ds_loai_lg, ds_pc', !v);
      setItemDisable(f, 'ds_sp, ds_cong, ds_tp, ds_tn_gt', v);
      setFieldsEmpty(f, 'ds_sp, ds_cong, ds_tp, ds_tn_gt', !v);
      break;
    case '4':
      setItemDisable(f, 'ds_bp, ds_loai_lg, ds_cong', !v);
      setItemDisable(f, 'ds_sp, ds_pc, ds_tp, ds_tn_gt', v);
      setFieldsEmpty(f, 'ds_sp, ds_pc, ds_tp, ds_tn_gt', !v);
      break;
    case '5':
      setItemDisable(f, 'ds_loai_lg, ds_tp', !v);
      setItemDisable(f, 'ds_bp, ds_sp, ds_pc, ds_cong, ds_tn_gt', v);
      setFieldsEmpty(f, 'ds_bp, ds_sp, ds_pc, ds_cong, ds_tn_gt', !v);
      break;
    case '6':
      setItemDisable(f, 'ds_loai_lg, ds_tn_gt', !v);
      setItemDisable(f, 'ds_bp, ds_sp, ds_pc, ds_cong, ds_tp', v);
      setFieldsEmpty(f, 'ds_bp, ds_sp, ds_pc, ds_cong, ds_tp', !v);
      break;
    case '7':
      setItemDisable(f, 'ds_bp, ds_cong', !v);
      setItemDisable(f, 'ds_loai_lg, ds_sp, ds_pc, ds_tp, ds_tn_gt', v);
      setFieldsEmpty(f, 'ds_loai_lg, ds_sp, ds_pc, ds_tp, ds_tn_gt', !v);
      t = true;
      break;
    default:
      break;
  }
  var k = (f.getItem('kind').value == 1); 
  setItemAllowNulls(f, (k && !t));
}
function onChange$CalculateType(f, force) {window.setTimeout(String.format('onFocus$CalculateType(\'{0}\', {1});', f._id, force ? 1 : 0), 2);}
function onFocus$CalculateType(id, force) {
  var f = $find(id), v = (f.getItem('kind').value == 2), t1 = f.getItem('nguon'), t2 = f.getItem('cach_tinh');
  setItemAllowNulls(f, !v);
  setFieldsEmpty(f, 'cach_tinh', v);
  setFieldsEmpty(f, 'ds_bp, ds_loai_lg, ds_sp, ds_pc', !v);
  if (force) setItemLive(t1, t2, !v);
  setItemDisable(f, 'cach_tinh', !v);
  setItemDisable(f, 'nguon, type, ds_bp, ds_loai_lg, ds_sp, ds_pc, ds_cong, ds_tp, ds_tn_gt', v);	
  if (f.getItem('kind').value == 1) onChange$Source(f);
}
function setItemLive(t1, t2, type) {
  if (type) {
    t1.disabled = false;
    t1.focus();
  }
  else {
    t2.disabled = false;
    t2.focus();
  }
}
function setItemAllowNulls(f, v) {
  var o = f.getItem('ds_loai_lg');
  o.field.AllowNulls = !v;	
  if (!v) f.setItemControlBehavior('ds_loai_lg', '', '');
  var grandNode = o.parentNode.parentNode;
  if (v) {
    Sys.UI.DomElement.addCssClass(grandNode, 'Required');
    Sys.UI.DomElement.addCssClass(grandNode, f._id);
  }
  else Sys.UI.DomElement.removeCssClass(grandNode, 'Required');
}
function setItemDisable(f, c, v) {
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    var o = f.getItem($func.trim(a[i]));
    if (o.a) $common.setVisible(o.a, !v);
    o.disabled = v;
  }
}
function setFieldsEmpty(f, c, v){
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    var o = f.getItem($func.trim(a[i]));
    if(!v) o.value = '';
  }
}

      &ScriptIrregular;
      &OutlineEntry;
